from __future__ import annotations

from dataclasses import dataclass
from typing import Iterable


@dataclass(frozen=True)
class FieldSpec:
    name: str
    minimum: int
    maximum: int


@dataclass(frozen=True)
class FieldPart:
    """One comma-separated piece of a cron field."""

    raw: str
    values: tuple[int, ...]
    step: int | None = None


@dataclass(frozen=True)
class CronField:
    spec: FieldSpec
    raw: str
    parts: tuple[FieldPart, ...]
    values: tuple[int, ...]

    @property
    def is_wildcard(self) -> bool:
        return self.values == tuple(range(self.spec.minimum, self.spec.maximum + 1))

    @property
    def single_value(self) -> int | None:
        return self.values[0] if len(self.values) == 1 else None

    @property
    def simple_step(self) -> int | None:
        """Return N for fields like */N, otherwise None."""
        if len(self.parts) != 1:
            return None

        part = self.parts[0]
        if not part.raw.startswith("*/"):
            return None

        return part.step


@dataclass(frozen=True)
class CronSchedule:
