    12: "December",
}


def parse_cron(expression: str) -> CronSchedule:
    fields = expression.split()

    if len(fields) != 5:
        raise ValueError(
            "Cron expression must contain exactly 5 fields: "
            "minute hour day_of_month month day_of_week"
        )

    parsed_fields = [
        parse_field(raw_field, spec)
        for raw_field, spec in zip(fields, FIELD_SPECS, strict=True)
    ]

    return CronSchedule(
        minute=parsed_fields[0],
        hour=parsed_fields[1],
        day_of_month=parsed_fields[2],
        month=parsed_fields[3],
        day_of_week=parsed_fields[4],
    )


def parse_field(raw_field: str, spec: FieldSpec) -> CronField:
    if not raw_field:
        raise ValueError(f"{spec.name} field cannot be empty")

    parts = tuple(parse_field_part(raw_part, spec) for raw_part in raw_field.split(","))
    values = sorted_unique(value for part in parts for value in part.values)

    return CronField(
        spec=spec,
        raw=raw_field,
        parts=parts,
        values=values,
    )


def parse_field_part(raw_part: str, spec: FieldSpec) -> FieldPart:
    if not raw_part:
        raise ValueError(f"{spec.name} field contains an empty list item")

    base_text, step = split_step(raw_part, spec)
    base_values = parse_base_values(base_text, spec)

    if step is not None:
        stepped_values = base_values[::step]
    else:
        stepped_values = base_values

    return FieldPart(
        raw=raw_part,
        values=tuple(stepped_values),
        step=step,
    )


def split_step(raw_part: str, spec: FieldSpec) -> tuple[str, int | None]:
    if "/" not in raw_part:
        return raw_part, None

    pieces = raw_part.split("/")
    if len(pieces) != 2:
        raise ValueError(f"{spec.name} field has invalid step syntax: {raw_part!r}")

    base_text, step_text = pieces
    if not base_text:
        raise ValueError(f"{spec.name} field step is missing a base range")
    if not step_text.isdigit():
        raise ValueError(f"{spec.name} field step must be a positive integer")

    step = int(step_text)
    if step <= 0:
        raise ValueError(f"{spec.name} field step must be greater than zero")

    return base_text, step


def parse_base_values(base_text: str, spec: FieldSpec) -> tuple[int, ...]:
    if base_text == "*":
        return tuple(range(spec.minimum, spec.maximum + 1))

    if "-" in base_text:
        return parse_range(base_text, spec)

    return (parse_number(base_text, spec),)


def parse_range(range_text: str, spec: FieldSpec) -> tuple[int, ...]:
    pieces = range_text.split("-")
    if len(pieces) != 2:
        raise ValueError(f"{spec.name} field has invalid range syntax: {range_text!r}")

    start = parse_number(pieces[0], spec)
    end = parse_number(pieces[1], spec)

    if start > end:
        raise ValueError(
            f"{spec.name} field range start cannot be greater than range end"
        )

    return tuple(range(start, end + 1))


def parse_number(text: str, spec: FieldSpec) -> int:
    if not text.isdigit():
        raise ValueError(f"{spec.name} field contains invalid value: {text!r}")

    value = int(text)
    if value < spec.minimum or value > spec.maximum:
        raise ValueError(
            f"{spec.name} field value {value} is outside "
            f"{spec.minimum}-{spec.maximum}"
        )

    return value


def sorted_unique(values: Iterable[int]) -> tuple[int, ...]:
    return tuple(sorted(set(values)))


def describe_time(hour: CronField, minute: CronField) -> str:
    if hour.single_value is not None and minute.single_value is not None:
        if hour.single_value == 0 and minute.single_value == 0:
            return "At midnight"
        return f"At {hour.single_value:02d}:{minute.single_value:02d}"

    if hour.is_wildcard and minute.single_value is not None:
        return f"At {minute.single_value} minutes past every hour"

    if minute.is_wildcard and hour.single_value is not None:
        return f"Every minute during hour {hour.single_value:02d}"

    return f"At {describe_field_values(hour)} hours and {describe_field_values(minute)} minutes"


def describe_date(
    day_of_month: CronField,
    month: CronField,
    day_of_week: CronField,
) -> str:
    pieces: list[str] = []

    if not day_of_month.is_wildcard:
        pieces.append(f"on {describe_ordinal_values(day_of_month.values)}")

    if not month.is_wildcard:
        month_text = describe_named_values(month.values, MONTH_NAMES)
        pieces.append(f"in {month_text}")

    if not day_of_week.is_wildcard:
        weekday_text = describe_named_values(day_of_week.values, DAY_NAMES)
        pieces.append(f"on {weekday_text}")

    if not pieces:
        return ""

    if day_of_month.single_value == 1 and month.is_wildcard and day_of_week.is_wildcard:
        return "on the 1st of every month"

    return " ".join(pieces)


def describe_field_values(field: CronField) -> str:
    return join_english([str(value) for value in field.values])


def describe_named_values(values: tuple[int, ...], names: dict[int, str]) -> str:
    if is_contiguous(values) and len(values) > 1:
        return f"{names[values[0]]} through {names[values[-1]]}"

    return join_english([names[value] for value in values])


def describe_ordinal_values(values: tuple[int, ...]) -> str:
    return join_english([f"the {ordinal(value)}" for value in values])


def is_contiguous(values: tuple[int, ...]) -> bool:
    return len(values) > 1 and values == tuple(range(values[0], values[-1] + 1))


def ordinal(value: int) -> str:
    if 10 <= value % 100 <= 20:
        suffix = "th"
    else:
        suffix = {1: "st", 2: "nd", 3: "rd"}.get(value % 10, "th")

    return f"{value}{suffix}"


def join_english(items: list[str]) -> str:
    if not items:
        return ""
    if len(items) == 1:
        return items[0]
    if len(items) == 2:
        return f"{items[0]} and {items[1]}"

    return f"{', '.join(items[:-1])}, and {items[-1]}"


